package calc.interpreter;

/**
 * Expression — interface every expression node must implement.
 *
 * DESIGN PRINCIPLE: Interface Segregation Principle (ISP)
 *   One method only — evaluate(). No node class is forced
 *   to implement anything it doesn't need.
 *
 * DESIGN PRINCIPLE: Dependency Inversion Principle (DIP)
 *   parser.Parser and Instructions depend on this interface, not on
 *   concrete node classes like NumberNode or BinaryOpNode.
 *
 * DESIGN PRINCIPLE: Polymorphism
 *   Call evaluate() on ANY expression node — each class does
 *   the right thing without the caller needing instanceof checks.
 *
 * Return types:
 *   Double  — arithmetic results and number literals
 *   String  — string literals
 *   Boolean — comparison results (>, <, ==)
 */
interface Expression {
    Object evaluate(Environment env);
}


// ─── NumberNode ───────────────────────────────────────────────────────────────
/**
 * Represents a numeric literal: 10  or  3.14
 *
 * DESIGN PRINCIPLE: Immutability
 *   value is private final — never changes after construction.
 *
 * DESIGN PRINCIPLE: SRP
 *   Stores one number, returns it. Nothing else.
 *
 * Leaf node — no children. Base case for recursive evaluation.
 */
final class NumberNode implements Expression {

    private final double value;

    public NumberNode(double value) {
        this.value = value;
    }

    @Override
    public Object evaluate(Environment env) {
        return value; // just return the stored number
    }

    @Override
    public String toString() {
        return "NumberNode(" + value + ")";
    }
}


// ─── StringNode ───────────────────────────────────────────────────────────────
/**
 * Represents a string literal: "hello"  or  "Pass"
 *
 * DESIGN PRINCIPLE: Immutability
 *   value is private final — never changes after construction.
 *
 * Leaf node — no children. Base case for recursive evaluation.
 */
final class StringNode implements Expression {

    private final String value;

    public StringNode(String value) {
        this.value = value;
    }

    @Override
    public Object evaluate(Environment env) {
        return value; // just return the stored string
    }

    @Override
    public String toString() {
        return "StringNode(\"" + value + "\")";
    }
}


// ─── VariableNode ─────────────────────────────────────────────────────────────
/**
 * Represents a variable reference: x  or  result  or  score
 *
 * DESIGN PRINCIPLE: Dependency Inversion
 *   Depends on Environment interface to look up values.
 *   Does not know HOW variables are stored — just asks Environment.
 *
 * DESIGN PRINCIPLE: Fail Fast
 *   If the variable was never defined, Environment throws
 *   RuntimeException immediately with a clear message.
 *
 * Leaf node — no children. Value is looked up at runtime.
 */
final class VariableNode implements Expression {

    private final String name; // variable name e.g. "x"

    public VariableNode(String name) {
        this.name = name;
    }

    @Override
    public Object evaluate(Environment env) {
        return env.get(name); // ask Environment for current value
    }

    @Override
    public String toString() {
        return "VariableNode(" + name + ")";
    }
}


// ─── BinaryOpNode ─────────────────────────────────────────────────────────────
/**
 * Represents an operation between two expressions.
 *
 * Examples:
 *   x + y * 2      arithmetic
 *   score > 50     comparison — returns Boolean
 *   a == b         equality   — returns Boolean
 *
 * Tree for x + y * 2:
 *
 *        BinaryOpNode("+")
 *        /               \
 *  VariableNode("x")   BinaryOpNode("*")
 *                      /               \
 *              VariableNode("y")   NumberNode(2)
 *
 * DESIGN PRINCIPLE: Recursion through Polymorphism
 *   evaluate() calls evaluate() on left and right children.
 *   Each child handles its own type — no instanceof needed.
 *
 * DESIGN PRINCIPLE: Immutability
 *   left, operator, right are all private final.
 *
 * Internal node — has two children (left and right).
 *
 * Return values:
 *   Arithmetic + - * /  →  Double
 *   Comparison > < ==   →  Boolean
 */
public final class BinaryOpNode implements Expression {

    private final Expression left;      // left-hand sub-expression
    private final String     operator;  // "+", "-", "*", "/", ">", "<", "=="
    private final Expression right;     // right-hand sub-expression

    public BinaryOpNode(Expression left, String operator, Expression right) {
        this.left     = left;
        this.operator = operator;
        this.right    = right;
    }

    @Override
    public Object evaluate(Environment env) {
        // Recursively evaluate both sides first
        Object leftVal  = left.evaluate(env);
        Object rightVal = right.evaluate(env);

        switch (operator) {

            // ── Arithmetic operators ──────────────────────────────────────
            case "+": return toDouble(leftVal) + toDouble(rightVal);
            case "-": return toDouble(leftVal) - toDouble(rightVal);
            case "*": return toDouble(leftVal) * toDouble(rightVal);
            case "/": {
                double divisor = toDouble(rightVal);
                if (divisor == 0) {
                    throw new RuntimeException(
                        "RUNTIME error: Division by zero"
                    );
                }
                return toDouble(leftVal) / divisor;
            }

            // ── Comparison operators ──────────────────────────────────────
            case ">":  return toDouble(leftVal) >  toDouble(rightVal);
            case "<":  return toDouble(leftVal) <  toDouble(rightVal);
            case "==": return toDouble(leftVal) == toDouble(rightVal);

            default:
                throw new RuntimeException(
                    "RUNTIME error: Unknown operator '" + operator + "'"
                );
        }
    }

    /** Safely cast Object to double — throws clear error if not a number. */
    private double toDouble(Object val) {
        if (val instanceof Double) return (Double) val;
        throw new RuntimeException(
            "RUNTIME error: Expected a number but got '"
            + val + "'"
        );
    }

    @Override
    public String toString() {
        return "BinaryOpNode(" + left + " " + operator + " " + right + ")";
    }
}

